Here's a minimal API endpoint that accepts multiple image files plus a text description via multipart form data:

```csharp
// Program.cs

var builder = WebApplication.CreateBuilder(args);

// Increase the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (IFormFileCollection files, HttpRequest request) =>
{
    var description = request.Form["description"].ToString();

    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var allowedTypes = new[] { "image/jpeg", "image/png", "image/gif", "image/webp" };
    var uploadPath = Path.Combine(app.Environment.ContentRootPath, "uploads");
    Directory.CreateDirectory(uploadPath);

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!allowedTypes.Contains(file.ContentType))
            return Results.BadRequest($"Invalid file type: {file.ContentType}");

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var filePath = Path.Combine(uploadPath, fileName);

        await using var stream = File.Create(filePath);
        await file.CopyToAsync(stream);

        saved.Add(fileName);
    }

    return Results.Ok(new { description, fileCount = saved.Count, fileNames = saved });
})
.DisableAntiforgery()
.Accepts<IFormFileCollection>("multipart/form-data");

app.Run();
```

**Key points:**

- `ConfigureKestrel` raises the body size limit to 50 MB (default is ~30 MB).
- The `IFormFileCollection` binding grabs all files from the form; `request.Form["description"]` reads the text field.
- `.DisableAntiforgery()` is needed for minimal APIs accepting form data without an antiforgery token.
- Content type is validated against an allowlist before saving.

**Example `curl` to test:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "files=@photo1.jpg" \
  -F "files=@photo2.png" \
  -F "description=Vacation photos"
```
